<template><div class="page"><h1>数据看板</h1><div class="stats"><div class="stat"><span class="muted">总订单数</span><b>{{d.totalOrders||0}}</b><p class="muted">全部历史订单</p></div><div class="stat"><span class="muted">今日新增</span><b>{{d.todayOrders||0}}</b><p class="muted">较昨日趋势待接入</p></div><div class="stat"><span class="muted">活跃司机</span><b>{{d.driverCount||0}}</b><p class="muted">注册司机总数</p></div><div class="stat"><span class="muted">用户数</span><b>{{d.userCount||0}}</b><p class="muted">注册用户总数</p></div></div><div class="card"><div class="toolbar" style="justify-content:space-between"><h2>近7天订单趋势</h2><span class="muted">演示趋势图</span></div><div ref="chartRef" style="height:280px"></div></div><div class="card"><div class="toolbar"><h2>最近订单</h2><el-button @click="load">刷新</el-button></div><el-table :data="orders" border><el-table-column prop="id" label="ID" width="80"/><el-table-column prop="userName" label="用户"/><el-table-column prop="driverName" label="司机"/><el-table-column prop="startAddress" label="起点"/><el-table-column prop="status" label="状态"/></el-table></div></div></template>
<script setup>import {nextTick,onMounted,ref} from 'vue';import * as echarts from 'echarts';import http from '../api/http';const d=ref({});const orders=ref([]);const chartRef=ref(null);async function load(){d.value=await http.get('/admin/dashboard');orders.value=(await http.get('/admin/orders')).slice(0,6);await nextTick();renderChart()}function renderChart(){const chart=echarts.init(chartRef.value);chart.setOption({color:['#ff6b35'],tooltip:{trigger:'axis'},grid:{left:36,right:18,top:30,bottom:30},xAxis:{type:'category',data:['D-6','D-5','D-4','D-3','D-2','D-1','今天']},yAxis:{type:'value'},series:[{type:'line',smooth:true,areaStyle:{color:'rgba(255,107,53,.12)'},data:[3,6,4,8,5,9,Number(d.value.todayOrders||0)]}]})}onMounted(load)</script>
